solutions.javascript:
// Solution
interface MathOperation<T> {
  add(x: T): T;
  subtract(x: T): T;
  multiply(x: T): T;
  divide(x: T): T;
}

class MathCalculator<T> implements MathOperation<T> {
  add(x: T): T {
    if (typeof x === 'number') {
      return x + 1;
    } else {
      return (x as string) + '1';
    }
  }

  subtract(x: T): T {
    if (typeof x === 'number') {
      return x - 1;
    } else {
      return (x as string) + '-1';
    }
  }

  multiply(x: T): T {
    if (typeof x === 'number') {
      return x * 2;
    } else {
      return (x as string) + '2';
    }
  }

  divide(x: T): T {
    if (typeof x === 'number') {
      if (x === 0) {
        return x;
      } else {
        return x / 2;
      }
    } else {
      return (x as string) + '/2';
    }
  }
}

const calculator = new MathCalculator<number>;
console.log(calculator.add(5)); // Output: 6
console.log(calculator.subtract(5)); // Output: 4
console.log(calculator.multiply(5)); // Output: 10
console.log(calculator.divide(5)); // Output: 2.5

// Now, try to call the calculator with a string argument
const stringCalculator = new MathCalculator<string>;
console.log(stringCalculator.add('a')); // Output: 'a1'
console.log(stringCalculator.subtract('a')); // Output: 'a-1'
console.log(stringCalculator.multiply('a')); // Output: 'a2'
console.log(stringCalculator.divide('a')); // Output: 'a/2'
